const item = $('Gemini blog writer').first().json;
const row = $('When called by scheduler').first().json;
let out = item.output ?? item.text ?? item;

if (typeof out === 'string') {
  let raw = out.trim();
  const fenced = raw.match(/```(?:json)?\s*([\s\S]*?)```/i);
  if (fenced) raw = fenced[1].trim();
  const start = raw.indexOf('{');
  const end = raw.lastIndexOf('}');
  if (start === -1 || end === -1) {
    throw new Error('Gemini did not return a JSON object');
  }
  out = JSON.parse(raw.slice(start, end + 1));
}

if (out && typeof out === 'object' && out.output && typeof out.output === 'object' && !out.slug) {
  out = out.output;
}

function fixCta(b, index) {
  const pillar = String(row.pillar_url || '/brain-surgery/').trim() || '/';
  const hrefDefault = index === 0 ? pillar : '/';
  const labelDefault = index === 0 ? 'Explore related services' : 'Book a consultation';

  if (b.href && b.text && !String(b.text).includes('href:')) {
    return {
      type: 'cta',
      text: String(b.text).trim() || labelDefault,
      href: String(b.href).trim() || hrefDefault,
    };
  }

  const raw = String(b.text || '');
  const hrefMatch = raw.match(/href:\s*([^,]+)/i);
  const textMatch = raw.match(/text:\s*(.+)$/i);
  return {
    type: 'cta',
    text: (textMatch?.[1] || labelDefault).trim() || labelDefault,
    href: (hrefMatch?.[1] || hrefDefault).trim() || hrefDefault,
  };
}

let ctaIndex = 0;

function sanitizeBlock(b) {
  if (!b || typeof b !== 'object') return null;
  const type = b.type;

  if (type === 'heading') {
    const text = String(b.text || '').trim();
    return text ? { type: 'heading', level: b.level === 3 ? 3 : 2, text } : null;
  }

  if (type === 'paragraph' || type === 'text') {
    const text = String(b.text || '').trim();
    return text ? { type: 'paragraph', text } : null;
  }

  if (type === 'list' || type === 'ordered-list') {
    const items = (b.items || []).map((x) => String(x).trim()).filter(Boolean);
    return items.length ? { type, items } : null;
  }

  if (type === 'cta') {
    const fixed = fixCta(b, ctaIndex);
    ctaIndex += 1;
    return fixed;
  }

  if (type === 'blockquote') {
    const text = String(b.text || '').trim();
    return text ? { type: 'blockquote', text } : null;
  }

  return null;
}

out.content = (out.content || []).map(sanitizeBlock).filter(Boolean);

if (!out.slug || !out.title || !Array.isArray(out.content) || !out.content.length) {
  throw new Error('Gemini JSON missing slug, title, or content after sanitize');
}

return [{ json: { output: out } }];

const out = $('Parse & sanitize JSON').first().json.output || {};
const row = $('When called by scheduler').first().json;

const STOP = new Set([
  'a','an','the','and','or','for','of','in','on','to','with','at','by','from','as','is','are','was','were','be','been','being',
]);

function slugify(s) {
  return String(s || '')
    .toLowerCase()
    .replace(/[^a-z0-9\s-]/g, '')
    .split(/\s+/)
    .filter((w) => w && !STOP.has(w))
    .join('-')
    .replace(/-+/g, '-')
    .replace(/^-|-$/g, '')
    .slice(0, 60);
}

function countBodyWords(blocks) {
  let n = 0;
  for (const b of blocks || []) {
    if (b.type === 'paragraph' && b.text) {
      n += String(b.text).split(/\s+/).filter(Boolean).length;
    }
    if ((b.type === 'list' || b.type === 'ordered-list') && Array.isArray(b.items)) {
      for (const item of b.items) {
        n += String(item).split(/\s+/).filter(Boolean).length;
      }
    }
    if (b.type === 'blockquote' && b.text) {
      n += String(b.text).split(/\s+/).filter(Boolean).length;
    }
  }
  return n;
}

function normalizeBlocks(blocks) {
  const outBlocks = [];
  for (const b of blocks || []) {
    if (!b || typeof b !== 'object') continue;
    if (b.type === 'text' || b.type === 'paragraph') {
      const t = String(b.text || '').trim();
      if (!t) continue;
      if (t.split(/\s+/).length < 15 && !t.includes('.')) {
        outBlocks.push({ type: 'heading', level: b.level === 3 ? 3 : 2, text: t });
      } else {
        outBlocks.push({ type: 'paragraph', text: t });
      }
      continue;
    }
    if (b.type === 'heading') {
      const level = b.level === 1 ? 2 : (b.level || 2);
      outBlocks.push({ type: 'heading', level, text: String(b.text || '').trim() });
      continue;
    }
    if (['list', 'ordered-list', 'cta', 'blockquote', 'image', 'html'].includes(b.type)) {
      outBlocks.push(b);
    }
  }
  return outBlocks;
}

function buildImagePrompt(row, out) {
  const topic = String(row.primary_keyword || out.title || 'neurosurgery').trim();
  const cluster = String(row.cluster || row.category || '').toLowerCase();
  let subjectFocus = 'precision neurosurgical care and advanced neural imaging';
  if (cluster.includes('spine') || cluster.includes('spinal')) {
    subjectFocus = 'spinal anatomy, vertebral structures, and minimally invasive spine care';
  } else if (cluster.includes('brain') || cluster.includes('tumour') || cluster.includes('tumor')) {
    subjectFocus = 'brain health, neural pathways, and high-resolution neuroimaging';
  } else if (cluster.includes('pituitary') || cluster.includes('endoscopic')) {
    subjectFocus = 'skull-base anatomy and endoscopic neurosurgical precision';
  }

  return (
    `Premium hero image for an authoritative neurosurgery medical website article: "${out.title}". `
    + `Clinical theme: ${topic}. Visual focus: ${subjectFocus}. `
    + `Style: cinematic editorial medical photography blended with photorealistic 3D volumetric anatomy — `
    + `rich depth, natural window light, soft shadow gradients, atmospheric haze, realistic material textures, `
    + `subtle film grain, magazine-quality composition. Sophisticated palette: warm ivory, soft charcoal, `
    + `muted teal and sage accents; full tonal range. `
    + `NOT flat vector illustration, NOT two-tone blue infographic, NOT clip art, NOT cartoon, `
    + `NOT generic stock photo, NOT sterile hospital corridor cliché. `
    + `Composition: wide cinematic 16:9, rule of thirds, shallow depth of field, clean modern neurology setting `
    + `with organic holographic scan elements integrated naturally into the scene. `
    + `Strict exclusions: no blood, no open surgery, no wounds, no identifiable patient or doctor faces, `
    + `no readable text, no logos, no watermarks.`
  );
}

const slug = slugify(out.slug || row.proposed_slug || row.primary_keyword);
if (!slug) throw new Error('Could not build SEO slug');

out.content = normalizeBlocks(out.content);
const paragraphCount = out.content.filter((b) => b.type === 'paragraph').length;
const words = countBodyWords(out.content);

if (paragraphCount < 10) {
  throw new Error(
    `Gemini returned an outline, not a full article: only ${paragraphCount} paragraph blocks. `
    + 'Regenerate. Need 10+ paragraph blocks with 70+ words each.'
  );
}
if (words < 1000) {
  throw new Error(
    `Article too short: ~${words} words in paragraphs (minimum 1000). Regenerate with full prose.`
  );
}

out.slug = slug;
out.title = String(out.title || row.proposed_title || '').trim();
if (!out.title) throw new Error('Gemini output missing title — check proposed_title on calendar row');
out.featuredImagePath = `assets/images/blog/${slug}.png`;
out.date = String(row.scheduled_date || new Date().toISOString().slice(0, 10)).slice(0, 10);
out.readingTimeMinutes = Math.max(8, Math.round(words / 200));
delete out.primaryKeyword;
delete out.wordCountEstimate;

return [{
  json: {
    ...row,
    normalized: out,
    word_count: words,
    paragraph_count: paragraphCount,
    image_prompt: buildImagePrompt(row, out),
  },
}];

const item = $input.first();
const row = $('Normalize blog output').first().json;

let image_base64 = item.json?.data?.[0]?.b64_json || item.json?.image_base64 || '';

// OpenAI Image node (filesystem binary mode) — binary property is usually "data"
if (!image_base64) {
  const binary = item.binary || {};
  const key = binary.data ? 'data' : Object.keys(binary)[0];
  if (!key) {
    throw new Error(
      'No image from OpenAI — expected binary property "data". '
      + 'Check Generate an image node output.'
    );
  }
  const buffer = await this.helpers.getBinaryDataBuffer(0, key);
  image_base64 = buffer.toString('base64');
}

if (!image_base64) throw new Error('Empty image data from OpenAI');

return [{ json: { ...row, image_base64 } }];

const row = $('Extract image base64').first().json;
const p = row.normalized;
const blocks = (p.content || []).filter((b) => b.type === 'paragraph').slice(0, 2);
const preview = blocks.map((b) => b.text).join('\n\n').slice(0, 400);

// chat_id: workflow 01 "Set calendar row" → scheduler trigger → Normalize → here
const cal = $('When called by scheduler').first().json;
const FALLBACK_CHAT_ID = '5131907549'; // your Telegram chat ID — keep in sync with workflow 01
const rowId = row.id ?? row.row_id ?? cal?.id;

const chatId = String(
  row.chat_id
  || row.telegram_chat_id
  || cal?.chat_id
  || cal?.telegram_chat_id
  || FALLBACK_CHAT_ID
).trim();

if (!chatId || chatId === 'REPLACE_WITH_YOUR_TELEGRAM_CHAT_ID') {
  throw new Error(
    'chat_id missing — open workflow 01, node "Set calendar row", set chat_id to your numeric Telegram ID'
  );
}

return [{
  json: {
    chat_id: chatId,
    row_id: rowId,
    slug: p.slug,
    image_base64: row.image_base64,
    preview_message:
      `📋 <b>Blog preview</b> (row ${rowId})\n\n`
      + `<b>Title:</b> ${p.title}\n`
      + `<b>Slug:</b> ${p.slug}\n`
      + `<b>Meta:</b> ${p.metaDescription}\n`
      + `<b>Words:</b> ~${row.word_count}\n`
      + `<b>Cluster:</b> ${row.cluster}\n`
      + `<b>Primary KW:</b> ${row.primary_keyword}\n\n`
      + `<b>Excerpt:</b>\n${preview}…`,
    callback_publish: `blog_publish_${rowId}`,
    callback_regen_article: `blog_regen_article_${rowId}`,
    callback_regen_image: `blog_regen_image_${rowId}`,
    callback_skip: `blog_skip_${rowId}`,
  },
}];

const item = $input.first().json;
const b64 = item.image_base64;
if (!b64) throw new Error('No image_base64 for Telegram photo');
